let noiseTex: DataTexture | undefined;

/** The shared randomizer texture, built once per run. */
export function getShaderNoiseTexture(): DataTexture {
  if (!noiseTex) {
    const raw = atob(NOISE_B64);
    const data = new Uint8Array(raw.length);
    for (let i = 0; i < raw.length; i++) data[i] = raw.charCodeAt(i);
    const tex = new DataTexture(data, NOISE_SIZE, NOISE_SIZE, RGBAFormat);
    tex.wrapS = ClampToEdgeWrapping;
    tex.wrapT = ClampToEdgeWrapping;
    tex.minFilter = LinearFilter;
    tex.magFilter = LinearFilter;
    tex.generateMipmaps = false;
    tex.needsUpdate = true;
    noiseTex = tex;
  }
  return noiseTex;
}
